//
//     final prettierrc = prettierrcFromJson(jsonString);

import 'dart:convert';

Prettierrc prettierrcFromJson(String str) => Prettierrc.fromJson(json.decode(str));

String prettierrcToJson(Prettierrc data) => json.encode(data.toJson());

class Prettierrc {
    int printWidth;
    int tabWidth;
    List<Override> overrides;

    Prettierrc({
        required this.printWidth,
        required this.tabWidth,
        required this.overrides,
    });

    factory Prettierrc.fromJson(Map<String, dynamic> json) => Prettierrc(
        printWidth: json["printWidth"],
        tabWidth: json["tabWidth"],
        overrides: List<Override>.from(json["overrides"].map((x) => Override.fromJson(x))),
    );

    Map<String, dynamic> toJson() => {
        "printWidth": printWidth,
        "tabWidth": tabWidth,
        "overrides": List<dynamic>.from(overrides.map((x) => x.toJson())),
    };
}

class Override {
    String files;
    Options options;

    Override({
        required this.files,
        required this.options,
    });

    factory Override.fromJson(Map<String, dynamic> json) => Override(
        files: json["files"],
        options: Options.fromJson(json["options"]),
    );

    Map<String, dynamic> toJson() => {
        "files": files,
        "options": options.toJson(),
    };
}

class Options {
    int tabWidth;

    Options({
        required this.tabWidth,
    });

    factory Options.fromJson(Map<String, dynamic> json) => Options(
        tabWidth: json["tabWidth"],
    );

    Map<String, dynamic> toJson() => {
        "tabWidth": tabWidth,
    };
}
